import React from 'react';
import { ArrowRight } from 'lucide-react';

interface ButtonProps {
  label: string;
  href: string;
  variant?: 'primary' | 'secondary' | 'outline';
  className?: string;
  icon?: boolean;
}

const Button: React.FC<ButtonProps> = ({ label, href, variant = 'primary', className = '', icon = true }) => {
  const baseStyles = "inline-flex items-center justify-center gap-2 px-6 py-3.5 rounded-[14px] font-medium transition-all duration-300 transform active:scale-95 text-sm md:text-base";

  const variants = {
    primary: "bg-primary text-white shadow-lg hover:shadow-xl hover:bg-black",
    secondary: "bg-white text-primary border border-border hover:border-accent hover:text-accent shadow-sm",
    outline: "border-2 border-primary text-primary hover:bg-primary hover:text-white"
  };

  return (
    <a 
      href={href} 
      className={`${baseStyles} ${variants[variant]} ${className}`}
    >
      {label}
      {icon && <ArrowRight size={18} />}
    </a>
  );
};

export default Button;

import React, { useState, useEffect } from 'react';
import { PageContent } from '../types';

interface HeaderProps {
  data: PageContent['header'];
}

const Header: React.FC<HeaderProps> = ({ data }) => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        scrolled ? 'bg-background/90 backdrop-blur-md border-b border-border py-3 shadow-sm' : 'bg-transparent py-5'
      }`}
    >
      <div className="container mx-auto px-4 md:px-6 flex items-center justify-between">
        <a href="#" className="font-serif font-semibold text-lg md:text-xl tracking-tight text-primary">
          {data.brand.logoText}
        </a>

        <div className="hidden md:block">
           <a 
            href={data.cta.href} 
            className="text-xs font-semibold tracking-wide uppercase px-5 py-2.5 border border-primary rounded-full hover:bg-primary hover:text-white transition-colors"
          >
            {data.cta.label}
          </a>
        </div>
      </div>
    </header>
  );
};

export default Header;

